class DatabaseConfig {
  static create() {
    const requiredEnvVars = ['DB_HOST', 'DB_NAME', 'DB_APP_USER', 'DB_APP_PASSWORD'];
    const missing = requiredEnvVars.filter(v => !process.env[v]);
    if (missing.length > 0) {
      throw new Error(`Missing required environment variables: ${missing.join(', ')}`);
    }

    const dbUser = process.env.DB_APP_USER;

    // SECURITY: Reject superuser connections from the application
    const FORBIDDEN_USERS = ['postgres', 'superuser', 'admin', 'root', 'rds_superuser'];
    if (FORBIDDEN_USERS.includes(dbUser.toLowerCase())) {
      throw new Error(
        `SECURITY VIOLATION: Application must NOT connect as superuser "${dbUser}". ` +
        `Create a dedicated application database user with least-privilege permissions.`
      );
    }

    return new Pool({
      host: process.env.DB_HOST,
      port: parseInt(process.env.DB_PORT || '5432', 10),
      database: process.env.DB_NAME,
      user: dbUser,
      password: process.env.DB_APP_PASSWORD,
      max: parseInt(process.env.DB_POOL_MAX || '20', 10),
      idleTimeoutMillis: 30000,
      connectionTimeoutMillis: 5000,
      ssl: process.env.DB_SSL === 'true' ? { rejectUnauthorized: true } : undefined,
      // Set search_path to the app schema only
      options: '-c search_path=app',
    });
  }
}

