class OrderRepository extends BaseRepository {
  async findAll(page = 1, limit = 20) {
    const { limit: safeLimit, offset } = Validator.validatePagination(page, limit);
    const countResult = await this.query('SELECT COUNT(*) FROM orders');
    const result = await this.query(
      `SELECT o.id, o.user_id, u.name as user_name, o.total, o.status, o.created_at, o.updated_at
       FROM orders o
       JOIN users u ON o.user_id = u.id
       ORDER BY o.id DESC LIMIT $1 OFFSET $2`,
      [safeLimit, offset]
    );
    return {
      data: result.rows,
      total: parseInt(countResult.rows[0].count, 10),
      page: parseInt(page, 10) || 1,
      limit: safeLimit,
    };
  }

  async findById(id) {
    if (!Validator.isPositiveInteger(id)) return null;

    const orderResult = await this.query(
      `SELECT o.id, o.user_id, u.name as user_name, u.email as user_email, 
              o.total, o.status, o.created_at, o.updated_at
       FROM orders o
       JOIN users u ON o.user_id = u.id
       WHERE o.id = $1`,
      [id]
    );

    if (orderResult.rows.length === 0) return null;

    const itemsResult = await this.query(
      `SELECT oi.id, oi.product_id, p.name as product_name, oi.quantity, oi.unit_price
       FROM order_items oi
       JOIN products p ON oi.product_id = p.id
       WHERE oi.order_id = $1
       ORDER BY oi.id`,
      [id]
    );

    return {
      ...orderResult.rows[0],
      items: itemsResult.rows,
    };
  }

  async findByUserId(userId, page = 1, limit = 20) {
    if (!Validator.isPositiveInteger(userId)) return { data: [], total: 0, page: 1, limit: 20 };
    const { limit: safeLimit, offset } = Validator.validatePagination(page, limit);

    const countResult = await this.query(
      'SELECT COUNT(*) FROM orders WHERE user_id = $1',
      [userId]
    );
    const result = await this.query(
      `SELECT id, user_id, total, status, created_at, updated_at
       FROM orders WHERE user_id = $1 ORDER BY id DESC LIMIT $2 OFFSET $3`,
      [userId, safeLimit, offset]
    );
    return {
      data: result.rows,
      total: parseInt(countResult.rows[0].count, 10),
      page: parseInt(page, 10) || 1,
      limit: safeLimit,
    };
  }

  async create({ userId, items }) {
    if (!Validator.isPositiveInteger(userId)) {
      throw new ValidationError('Invalid user ID');
    }
    if (!Array.isArray(items) || items.length === 0) {
      throw new ValidationError('Order must contain at least one item');
    }
    if (items.length > 100) {
      throw new ValidationError('Order cannot contain more than 100 items');
    }

    // Validate all items before starting transaction
    for (const item of items) {
      if (!Validator.isPositiveInteger(item.productId)) {
        throw new ValidationError('Invalid product ID in order items');
      }
      if (!Validator.isPositiveInteger(item.quantity)) {
        throw new ValidationError('Quantity must be a positive integer');
      }
    }

    return this.transaction(async (client) => {
      // Verify user exists
      const userCheck = await client.query('SELECT id FROM users WHERE id = $1', [userId]);
      if (userCheck.rows.length === 0) {
        throw new NotFoundError('User not found');
      }

      let total = 0;
      const orderItems = [];

      for (const item of items) {
        // Lock the product row to prevent race conditions on stock
        const productResult = await client.query(
          'SELECT id, name, price, stock FROM products WHERE id = $1 FOR UPDATE',
          [item.productId]
        );

        if (productResult.rows.length === 0) {
          throw new NotFoundError(`Product with ID ${item.productId} not found`);
        }

        const product = productResult.rows[0];
        const quantity = parseInt(item.quantity, 10);

        if (product.stock < quantity) {
          throw new ValidationError(
            `Insufficient stock for product "${product.name}". Available: ${product.stock}, Requested: ${quantity}`
          );
        }

        // Decrease stock
        await client.query(
          'UPDATE products SET stock = stock - $1, updated_at = NOW() WHERE id = $2',
          [quantity, product.id]
        );

        const unitPrice = parseFloat(product.price);
        total += unitPrice * quantity;

        orderItems.push({
          productId: product.id,
          quantity,
          unitPrice,
        });
      }

      // Create order
      const orderResult = await client.query(
        `INSERT INTO orders (user_id, total, status) VALUES ($1, $2, 'pending')
         RETURNING id, user_id, total, status, created_at, updated_at`,
        [userId, total.toFixed(2)]
      );

      const order = orderResult.rows[0];

      // Create order items
      const insertedItems = [];
      for (const item of orderItems) {
        const itemResult = await client.query(
          `INSERT INTO order_items (order_id, product_id, quantity, unit_price)
           VALUES ($1, $2, $3, $4)
           RETURNING id, order_id, product_id, quantity, unit_price`,
          [order.id, item.productId, item.quantity, item.unitPrice]
        );
        insertedItems.push(itemResult.rows[0]);
      }

      return { ...order, items: insertedItems };
    });
  }

  async updateStatus(id, status) {
    if (!Validator.isPositiveInteger(id)) {
      throw new ValidationError('Invalid order ID');
    }
    if (!Validator.isValidOrderStatus(status)) {
      throw new ValidationError(`Invalid status. Must be one of: pending, confirmed, shipped, delivered, cancelled`);
    }

    const result = await this.query(
      `UPDATE orders SET status = $1, updated_at = NOW() WHERE id = $2
       RETURNING id, user_id, total, status, created_at, updated_at`,
      [status, id]
    );
    return result.rows[0] || null;
  }

  async delete(id) {
    if (!Validator.isPositiveInteger(id)) {
      throw new ValidationError('Invalid order ID');
    }

    return this.transaction(async (client) => {
      const orderResult = await client.query(
        'SELECT id, status FROM orders WHERE id = $1 FOR UPDATE',
        [id]
      );

      if (orderResult.rows.length === 0) return false;

      const order = orderResult.rows[0];
      if (order.status !== 'pending') {
        throw new ValidationError('Only pending orders can be deleted');
      }

      // Restore stock for order items
      const items = await client.query(
        'SELECT product_id, quantity FROM order_items WHERE order_id = $1',
        [id]
      );

      for (const item of items.rows) {
        await client.query(
          'UPDATE products SET stock = stock + $1, updated_at = NOW() WHERE id = $2',
          [item.quantity, item.product_id]
        );
      }

      // CASCADE will delete order_items
      await client.query('DELETE FROM orders WHERE id = $1', [id]);
      return true;
    });
  }
}

// ============================================================
// Custom Error Classes
// ============================================================

class ValidationError extends Error {
  constructor(message) {
    super(message);
    this.name = 'ValidationError';
    this.statusCode = 400;
  }
}

class NotFoundError extends Error {
  constructor(message) {
    super(message);
    this.name = 'NotFoundError';
    this.statusCode = 404;
  }
}

class ConflictError extends Error {
  constructor(message) {
    super(message);
    this.name = 'ConflictError';
    this.statusCode = 409;
  }
}

