function createApp(pool) {
  const app = express();

  // Security middleware
  app.use(helmet());
  app.use(express.json({ limit: '10kb' }));

  // Rate limiting
  const limiter = rateLimit({
    windowMs: 15 * 60 * 1000,
    max: 100,
    standardHeaders: true,
    legacyHeaders: false,
    message: { error: 'Too many requests, please try again later' },
  });
  app.use(limiter);

  // Disable fingerprinting
  app.disable('x-powered-by');

  // Initialize repositories
  const userRepo = new UserRepository(pool);
  const productRepo = new ProductRepository(pool);
  const orderRepo = new OrderRepository(pool);

  // ---- Health Check ----
  app.get('/health', async (req, res) => {
    try {
      await pool.query('SELECT 1');
      res.json({ status: 'healthy', timestamp: new Date().toISOString() });
    } catch (error) {
      res.status(503).json({ status: 'unhealthy', timestamp: new Date().toISOString() });
    }
  });

  // ---- User Routes ----
  app.get('/api/users', async (req, res, next) => {
    try {
      const result = await userRepo.findAll(req.query.page, req.query.limit);
      res.json(result);
    } catch (error) {
      next(error);
    }
  });

  app.get('/api/users/:id', async (req, res, next) => {
    try {
      const user = await userRepo.findById(req.params.id);
      if (!user) return res.status(404).json({ error: 'User not found' });
      res.json(user);
    } catch (error) {
      next(error);
    }
  });

  app.post('/api/users', async (req, res, next) => {
    try {
      const user = await userRepo.create(req.body);
      res.status(201).json(user);
    } catch (error) {
      if (error.code === '23505') {
        return res.status(409).json({ error: 'A user with this email already exists' });
      }
      next(error);
    }
  });

  app.put('/api/users/:id', async (req, res, next) => {
    try {
      const user = await userRepo.update(req.params.id, req.body);
      if (!user) return res.status(404).json({ error: 'User not found' });
      res.json(user);
    } catch (error) {
      if (error.code === '23505') {
        return res.status(409).json({ error: 'A user with this email already exists' });
      }
      next(error);
    }
  });

  app.delete('/api/users/:id', async (req, res, next) => {
    try {
      const deleted = await userRepo.delete(req.params.id);
      if (!deleted) return res.status(404).json({ error: 'User not found' });
      res.status(204).send();
    } catch (error) {
      if (error.code === '23503') {
        return res.status(409).json({ error: 'Cannot delete user with existing orders' });
      }
      next(error);
    }
  });

  // ---- Product Routes ----
  app.get('/api/products', async (req, res, next) => {
    try {
      const result = await productRepo.findAll(req.query.page, req.query.limit);
      res.json(result);
    } catch (error) {
      next(error);
    }
  });

  app.get('/api/products/:id', async (req, res, next) => {
    try {
      const product = await productRepo.findById(req.params.id);
      if (!product) return res.status(404).json({ error: 'Product not found' });
      res.json(product);
    } catch (error) {
      next(error);
    }
  });

  app.post('/api/products', async (req, res, next) => {
    try {
      const product = await productRepo.create(req.body);
      res.status(201).json(product);
    } catch (error) {
      next(error);
    }
  });

  app.put('/api/products/:id', async (req, res, next) => {
    try {
      const product = await productRepo.update(req.params.id, req.body);
      if (!product) return res.status(404).json({ error: 'Product not found' });
      res.json(product);
    } catch (error) {
      next(error);
    }
  });

  app.delete('/api/products/:id', async (req, res, next) => {
    try {
      const deleted = await productRepo.delete(req.params.id);
      if (!deleted) return res.status(404).json({ error: 'Product not found' });
      res.status(204).send();
    } catch (error) {
      if (error.code === '23503') {
        return res.status(409).json({ error: 'Cannot delete product that is part of existing orders' });
      }
      next(error);
    }
  });

  // ---- Order Routes ----
  app.get('/api/orders', async (req, res, next) => {
    try {
      const result = await orderRepo.findAll(req.query.page, req.query.limit);
      res.json(result);
    } catch (error) {
      next(error);
    }
  });

  app.get('/api/orders/:id', async (req, res, next) => {
    try {
      const order = await orderRepo.findById(req.params.id);
      if (!order) return res.status(404).json({ error: 'Order not found' });
      res.json(order);
    } catch (error) {
      next(error);
    }
  });

  app.get('/api/users/:userId/orders', async (req, res, next) => {
    try {
      const result = await orderRepo.findByUserId(req.params.userId, req.query.page, req.query.limit);
      res.json(result);
    } catch (error) {
      next(error);
    }
  });

  app.post('/api/orders', async (req, res, next) => {
    try {
      const order = await orderRepo.create({
        userId: req.body.userId,
        items: req.body.items,
      });
      res.status(201).json(order);
    } catch (error) {
      next(error);
    }
  });

  app.patch('/api/orders/:id/status', async (req, res, next) => {
    try {
      const order = await orderRepo.updateStatus(req.params.id, req.body.status);
      if (!order) return res.status(404).json({ error: 'Order not found' });
      res.json(order);
    } catch (error) {
      next(error);
    }
  });

  app.delete('/api/orders/:id', async (req, res, next) => {
    try {
      const deleted = await orderRepo.delete(req.params.id);
      if (!deleted) return res.status(404).json({ error: 'Order not found' });
      res.status(204).send();
    } catch (error) {
      next(error);
    }
  });

  // ---- Global Error Handler ----
  app.use((err, req, res, next) => {
    // Log the full error server-side
    console.error(`[${new Date().toISOString()}] Error:`, {
      message: err.message,
      stack: process.env.NODE_ENV === 'development' ? err.stack : undefined,
      path: req.path,
      method: req.method,
    });

    if (err instanceof ValidationError) {
      return res.status(400).json({ error: err.message });
    }
    if (err instanceof NotFoundError) {
      return res.status(404).json({ error: err.message });
    }
    if (err instanceof ConflictError) {
      return res.status(409).json({ error: err.message });
    }

    // PostgreSQL constraint violations
    if (err.code === '23505') {
      return res.status(409).json({ error: 'Resource already exists' });
    }
    if (err.code === '23503') {
      return res.status(409).json({ error: 'Referenced resource not found or resource is in use' });
    }
    if (err.code === '23514') {
      return res.status(400).json({ error: 'Data constraint violation' });
    }

    // Do NOT leak internal error details to clients
    res.status(500).json({ error: 'Internal server error' });
  });

  // 404 handler
  app.use((req, res) => {
    res.status(404).json({ error: 'Endpoint not found' });
  });

  return app;
}

// ============================================================
// Application Entry Point
// ============================================================

async function main() {
  let pool;

  try {
    pool = DatabaseConfig.create();

    // Verify connectivity
    const client = await pool.connect();
    const result = await client.query('SELECT current_user, current_database()');
    console.log(`Connected to database "${result.rows[0].current_database}" as user "${result.rows[0].current_user}"`);
    client.release();

    const app = createApp(pool);

    const port = parseInt(process.env.PORT || '3000', 10);
    const host = process.env.HOST || '127.0.0.1';

    const server = app.listen(port, host, () => {
      console.log(`Server running on http://${host}:${port}`);
      console.log(`Environment: ${process.env.NODE_ENV || 'development'}`);
    });

    // Graceful shutdown
    const shutdown = async (signal) => {
      console.log(`\n${signal} received. Starting graceful shutdown...`);
      server.close(async () => {
        console.log('HTTP server closed');
        await pool.end();
        console.log('Database pool closed');
        process.exit(0);
      });

      // Force shutdown after 30 seconds
      setTimeout(() => {
        console.error('Forced shutdown after timeout');
        process.exit(1);
      }, 30000);
    };

    process.on('SIGTERM', () => shutdown('SIGTERM'));
    process.on('SIGINT', () => shutdown('SIGINT'));

    // Handle unhandled rejections
    process.on('unhandledRejection', (reason) => {
      console.error('Unhandled Rejection:', reason);
    });

  } catch (error) {
    console.error('Failed to start application:', error.message);
    if (pool) await pool.end();
    process.exit(1);
  }
}

main();

module.exports = { createApp, DatabaseConfig, UserRepository, ProductRepository, OrderRepository, Validator, ValidationError, NotFoundError, ConflictError };